const input = $input.first().json;
const action = input.action || 'get_report';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json'
};

async function getGoogleToken() {
  const creds = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&select=cred_key,cred_value',
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
  });
  const m = {};
  for (const c of creds) m[c.cred_key] = c.cred_value;
  if (!m.access_token || !m.refresh_token) throw new Error('Google OAuth not configured.');
  if (new Date(m.token_expiry || 0) <= new Date(Date.now() + 5 * 60 * 1000)) {
    const resp = await helpers.httpRequest({
      method: 'POST', url: 'https://oauth2.googleapis.com/token',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: 'grant_type=refresh_token&refresh_token=' + encodeURIComponent(m.refresh_token) + '&client_id=' + encodeURIComponent(m.client_id) + '&client_secret=' + encodeURIComponent(m.client_secret)
    });
    if (resp.error) throw new Error('Token refresh failed: ' + resp.error_description);
    const newExpiry = new Date(Date.now() + (resp.expires_in - 60) * 1000).toISOString();
    for (const [key, val] of [['access_token', resp.access_token], ['token_expiry', newExpiry]]) {
      await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&cred_key=eq.' + key, headers: { ...pgHeaders, 'Prefer': 'return=minimal' } });
      await helpers.httpRequest({ method: 'POST', url: SUPABASE_URL + '/rest/v1/template_credentials', headers: { ...pgHeaders, 'Prefer': 'return=minimal' }, body: JSON.stringify({ template_id: 'google-oauth', cred_key: key, cred_value: val }) });
    }
    if (resp.refresh_token) {
      await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&cred_key=eq.refresh_token', headers: { ...pgHeaders, 'Prefer': 'return=minimal' } });
      await helpers.httpRequest({ method: 'POST', url: SUPABASE_URL + '/rest/v1/template_credentials', headers: { ...pgHeaders, 'Prefer': 'return=minimal' }, body: JSON.stringify({ template_id: 'google-oauth', cred_key: 'refresh_token', cred_value: resp.refresh_token }) });
    }
    return resp.access_token;
  }
  return m.access_token;
}

let accessToken;
try { accessToken = await getGoogleToken(); } catch(e) { return [{ json: { error: e.message } }]; }

const gHeaders = { 'Authorization': 'Bearer ' + accessToken, 'Content-Type': 'application/json' };

// === get_report ===
if (action === 'get_report') {
  const propertyId = input.property_id;
  const dateFrom = input.date_from;
  const dateTo = input.date_to;
  if (!propertyId || !dateFrom || !dateTo) return [{ json: { error: 'Parameters "property_id", "date_from" (YYYY-MM-DD), and "date_to" (YYYY-MM-DD) are required.' } }];

  const metricsStr = input.metrics || 'sessions,activeUsers,screenPageViews';
  const metrics = metricsStr.split(',').map(m => ({ name: m.trim() }));

  const body = {
    dateRanges: [{ startDate: dateFrom, endDate: dateTo }],
    metrics
  };

  if (input.dimensions) {
    body.dimensions = input.dimensions.split(',').map(d => ({ name: d.trim() }));
  }

  try {
    const resp = await helpers.httpRequest({
      method: 'POST',
      url: 'https://analyticsdata.googleapis.com/v1beta/properties/' + propertyId + ':runReport',
      headers: gHeaders,
      body: JSON.stringify(body)
    });

    if (!resp.rows || resp.rows.length === 0) return [{ json: { result: 'No data found for the given date range and metrics.' } }];

    const dimHeaders = (resp.dimensionHeaders || []).map(h => h.name);
    const metricHeaders = (resp.metricHeaders || []).map(h => h.name);

    let result = 'GA4 Report for property ' + propertyId + ' (' + dateFrom + ' to ' + dateTo + '):\n\n';
    result += '| ' + [...dimHeaders, ...metricHeaders].join(' | ') + ' |\n';
    result += '| ' + [...dimHeaders, ...metricHeaders].map(() => '---').join(' | ') + ' |\n';

    for (const row of resp.rows.slice(0, 50)) {
      const dims = (row.dimensionValues || []).map(v => v.value);
      const mets = (row.metricValues || []).map(v => v.value);
      result += '| ' + [...dims, ...mets].join(' | ') + ' |\n';
    }

    if (resp.rowCount > 50) result += '\n... showing 50 of ' + resp.rowCount + ' rows.';
    if (resp.totals && resp.totals.length > 0) {
      result += '\n\nTotals: ' + resp.totals[0].metricValues.map((v, i) => metricHeaders[i] + '=' + v.value).join(', ');
    }
    return [{ json: { result } }];
  } catch(e) { return [{ json: { error: 'GA4 report failed: ' + e.message } }]; }

// === list_properties ===
} else if (action === 'list_properties') {
  try {
    const resp = await helpers.httpRequest({
      method: 'GET',
      url: 'https://analyticsadmin.googleapis.com/v1beta/accountSummaries?pageSize=200',
      headers: gHeaders
    });

    if (!resp.accountSummaries || resp.accountSummaries.length === 0) return [{ json: { result: 'No GA4 properties found.' } }];

    let result = 'GA4 Properties:\n\n';
    for (const acct of resp.accountSummaries) {
      result += '**Account: ' + acct.displayName + '** (' + acct.account + ')\n';
      if (acct.propertySummaries) {
        for (const p of acct.propertySummaries) {
          const id = p.property.replace('properties/', '');
          result += '  - ' + p.displayName + ' (Property ID: ' + id + ')\n';
        }
      }
      result += '\n';
    }
    return [{ json: { result } }];
  } catch(e) { return [{ json: { error: 'Failed to list properties: ' + e.message } }]; }

// === get_realtime_data ===
} else if (action === 'get_realtime_data') {
  const propertyId = input.property_id;
  if (!propertyId) return [{ json: { error: 'Parameter "property_id" is required.' } }];

  const metricsStr = input.metrics || 'activeUsers,screenPageViews';
  const metrics = metricsStr.split(',').map(m => ({ name: m.trim() }));

  try {
    const resp = await helpers.httpRequest({
      method: 'POST',
      url: 'https://analyticsdata.googleapis.com/v1beta/properties/' + propertyId + ':runRealtimeReport',
      headers: gHeaders,
      body: JSON.stringify({
        metrics,
        dimensions: [{ name: 'unifiedScreenName' }]
      })
    });

    if (!resp.rows || resp.rows.length === 0) return [{ json: { result: 'No realtime data available.' } }];

    let result = 'Realtime Data for property ' + propertyId + ':\n\n';
    const metricHeaders = (resp.metricHeaders || []).map(h => h.name);

    if (resp.totals && resp.totals.length > 0) {
      result += 'Totals: ' + resp.totals[0].metricValues.map((v, i) => metricHeaders[i] + '=' + v.value).join(', ') + '\n\n';
    }

    result += 'By Page:\n';
    for (const row of resp.rows.slice(0, 20)) {
      const page = (row.dimensionValues || [{}])[0].value || '(unknown)';
      const vals = (row.metricValues || []).map(v => v.value);
      result += '- ' + page + ': ' + vals.map((v, i) => metricHeaders[i] + '=' + v).join(', ') + '\n';
    }
    return [{ json: { result } }];
  } catch(e) { return [{ json: { error: 'Realtime report failed: ' + e.message } }]; }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: get_report, list_properties, get_realtime_data.' } }];
}
